    '''Fixed version'''
    def entry(i, j):
        if j < pos:
            return (i, j, 'self')  # self[i, j]
        elif pos <= j < pos + other_cols:
            return (i, j - pos, 'other')  # other[i, j - pos]
        return (i, j - other_cols, 'self')  # self[i, j - other_cols]
    return entry

# Test: self is 6x6 identity, other is 6x2, pos=3
